import React, { useEffect } from 'react';

const Parallax = ({ images }) => {
    useEffect(() => {
        const handleScroll = () => {
            let value = window.scrollY;

            images.forEach(image => {
                const element = document.querySelector(`.${image.imgSrc}`);
                if (element) {
                    element.style.marginTop = (value * image.imgSpeed) + image.imgOffset + 'px';
                }
            });
        };

        document.addEventListener('scroll', handleScroll);

        return () => {
            document.removeEventListener('scroll', handleScroll);
        };
    }, [images]);

    return (
        <div>
            {images.map(image => (
                <img key={image.imgSrc} src={image.imgSrc} alt="" className={image.imgSrc} />
            ))}
        </div>
    );
};

export default Parallax;
